const report = $input.first().json;

const total = report.total_products ?? 0;
const eliminated = report.eliminated ?? 0;
const averageScore = report.average_score ?? "غير متوفر";

const rec = report.by_recommendation || {};
const rejected = rec.Reject ?? 0;
const watchlist = rec.Watchlist ?? 0;
const smallBudget = rec["Test with small budget"] ?? 0;
const strong = rec["Strong candidate"] ?? 0;

const candidates = Array.isArray(report.top_candidates)
  ? report.top_candidates
  : [];

const topList = candidates.length
  ? candidates
      .map((p, i) => `${i + 1}. ${p.name} — score: ${p.score} — ${p.recommendation}`)
      .join("\n")
  : "لا يوجد مرشحون واضحون اليوم.";

let decision = "";

if (smallBudget > 0) {
  decision = "كاين منتجات تستحق اختبار صغير، ولكن مازال ما كاين حتى منتج قوي بما يكفي لميزانية كبيرة.";
} else if (watchlist > 0) {
  decision = "الأفضل اليوم هو المراقبة فقط وعدم صرف ميزانية إعلانية.";
} else {
  decision = "النتائج ضعيفة اليوم، والأفضل رفض أغلب المنتجات ومواصلة البحث.";
}

const summary = `
تقرير المنتجات اليومي:

- عدد المنتجات المحللة: ${total}
- المنتجات المرفوضة: ${rejected}
- المنتجات في قائمة المراقبة: ${watchlist}
- المنتجات المناسبة لاختبار صغير: ${smallBudget}
- المنتجات القوية: ${strong}
- المنتجات المستبعدة: ${eliminated}
- متوسط السكور: ${averageScore}

أفضل المرشحين:
${topList}

القرار:
${decision}

التوصية العملية اليوم:
لا تصرف ميزانية كبيرة. ركّز فقط على المنتجات التي حصلت على "Test with small budget"، وابدأ باختبار صغير جدًا حتى يظهر دليل طلب حقيقي من السوق الأمريكي.
`.trim();

return [
  {
    json: {
      summary_ar: summary,
      total_products: total,
      rejected,
      watchlist,
      small_budget_tests: smallBudget,
      strong_candidates: strong,
      top_candidates: candidates
    }
  }
];

const candidates = $json.candidates || [];

return candidates.map(product => ({
  json: product
}));

const inserted = $input.all();

return [
  {
    json: {
      status: "products_inserted",
      inserted_count: inserted.length,
      inserted_ids: inserted.map(item => item.json.id),
      message: "Products inserted successfully. Continue to daily report."
    }
  }
];
